export default function ListItem(props) {

    const {state} = useWeb3();
    const {web3Instance,Account} = state;

    const switchTime = (dateTime) =>{
        const daytime = parseInt(dateTime) * 1000;
        var timestamp1 = new Date(daytime).toLocaleString();
        return timestamp1.split(",")[0];
    }

    const toThousands = (str) => {
        let balance = web3Instance.web3Instance.utils.fromWei(str);
        return  PublicObj.ToThousands(balance);
    }

    const { openBox, openModal, Itemdata} = props;
    const { spname, logo, name, desc, share, status, created, period, totalReward, totalStake, threshold,id } = Itemdata;

    return (
        <Librdr>
            <FirstRow>
                <LftT>
                    <Avatar src={logo} width="28px"/>
                    <Author>by {spname}</Author>
                </LftT>
                    {
                        status === '1' && <RhtT>
                            <img src={inProgress} alt=""/>
                            <ProgressDiv>Staking in progress</ProgressDiv>
                        </RhtT>
                    }
                    {
                        status === '3' && <RhtT>
                            <img src={failedImg} alt=""/>
                            <FailDiv>Failed</FailDiv>
                        </RhtT>
                    }
                    {
                        status === '0' && <RhtT>
                            <img src={auditImg} alt=""/>
                            <AuditDiv>Created {switchTime(created)}</AuditDiv>
                        </RhtT>
                    }
                    {
                        status === '2' && <RhtT>
                            <img src={endingImg} alt=""/>
                            <EndDiv>Finished</EndDiv>
                        </RhtT>
                    }

            </FirstRow>
            <div>
                <Titles>{name}</Titles>
                <ContentS>{desc}</ContentS>
                <Ul>
                    <Li>
                        <Star>*</Star>
                        <Names>Share</Names>
                        <PercentS>{share}%</PercentS>
                    </Li>
                    <Li>
                        <Star>*</Star>
                        <Names>Estimate Apy</Names>
                        <PercentS>{PublicObj.handleApy(totalReward, totalStake, period)}%</PercentS>
                    </Li>
                </Ul>
                <div>
                    <PercentBg>
                        <Active style={{width: PublicObj.handleWidth(totalStake,threshold)  + '%'}} />
                    </PercentBg>
                    <Texts>
                        <span>Period: { PublicObj.SecondToDay(period)} Days</span>
                        <span>{toThousands(totalStake)} / {toThousands(threshold)} APN</span>
                    </Texts>
                </div>
            </div>
            <LastRow>
                <Btn onClick={()=>openModal(id,name)} disabled={status !== '0' || Account == null} >Stake</Btn>
                <Rhta onClick={()=>openBox(id)}>Details</Rhta>
            </LastRow>
        </Librdr>
    );

}
