const ToThousands =  (str) =>{
    var newStr = "";
    var count = 0;
    if (str.indexOf(".") === -1) {
        for (let i = str.length - 1; i >= 0; i--) {
            if (count % 3 === 0 && count !== 0) {
                newStr = str.charAt(i) + "," + newStr;
            } else {
                newStr = str.charAt(i) + newStr;
            }
            count++;
        }
        str = newStr ;
        return str;
    }
    else {
        for (let i = str.indexOf(".") - 1; i >= 0; i--) {
            if (count % 3 === 0 && count !== 0) {
                newStr = str.charAt(i) + "," + newStr;
            } else {
                newStr = str.charAt(i) + newStr;
            }
            count++;
        }
        str = newStr + (str + "00").substr((str + "00").indexOf("."), 3);
        return str;
    }
    return newStr;
}

const SecondToDay = (time)=>{
    return Math.ceil(time / (60 * 60 * 24));
    // return (time / (60 * 60 * 24)).toFixed(2);
}

const handleApy = (totalReward, totalStake ,period) => {
    let apy;
    if( totalReward * totalStake * period){
        apy = totalReward / totalStake * (365/ (period/(60 * 60 * 24))) * 100;
    } else {
        apy = 0;
    }
    return apy;
}

const handleWidth = (totalStake,threshold) =>{
    if (totalStake >= threshold) {
        return 100;
    }
    return (totalStake/threshold) * 100;
}


const PublicObj = {
    ToThousands,
    SecondToDay,
    handleApy,
    handleWidth
}

export default PublicObj;
